const input = $input.first().json;
const body = input.body || input;

const enquiry = (body.enquiry || body.message || body.text || '').trim();
const senderName = (body.sender_name || body.name || 'Unknown Client').trim();
const senderEmail = (body.sender_email || body.email || '').trim();
const senderPhone = (body.sender_phone || body.phone || '').trim();

if (!enquiry) {
  return [{
    json: {
      valid: false,
      error: 'missing_enquiry',
      message: 'No enquiry text provided. Include an "enquiry" field in your request body.'
    }
  }];
}

if (enquiry.length < 10) {
  return [{
    json: {
      valid: false,
      error: 'enquiry_too_short',
      message: 'Enquiry text is too short (minimum 10 characters). Please provide more detail.'
    }
  }];
}

if (enquiry.length > 5000) {
  return [{
    json: {
      valid: false,
      error: 'enquiry_too_long',
      message: `Enquiry exceeds 5000 character limit (received ${enquiry.length} chars). Please summarise your enquiry.`
    }
  }];
}

return [{
  json: {
    valid: true,
    enquiry: enquiry,
    sender_name: senderName,
    sender_email: senderEmail,
    sender_phone: senderPhone,
    timestamp: new Date().toISOString()
  }
}];

const data = $input.first().json;

const systemPrompt = `You are an AI assistant for Strata Management Consultants, a strata property management company based in Australia. Your role is to analyse incoming client enquiries and provide structured guidance to help staff respond quickly and accurately.

Analyse the client enquiry provided and return a single JSON object with EXACTLY these fields (no extra text, no markdown, no code blocks):

{
  "classification": "<one of: new_client_enquiry | support_request | complaint | general_question | billing_enquiry | maintenance_request | legal_matter | urgent_matter>",
  "confidence": <decimal 0.0 to 1.0 — how certain you are of the classification>,
  "urgency": "<one of: low | medium | high>",
  "summary": "<one-sentence summary of what the client needs, max 120 characters>",
  "key_details": ["<key point 1>", "<key point 2>", "..."],
  "suggested_response": "<professional email response draft the staff member can send or personalise — use [Staff Name] as placeholder for sender, address the client by their name if provided>",
  "recommended_action": "<concrete next step the staff member should take, e.g. 'Schedule callback within 24 hours', 'Forward to accounts team', 'Escalate to senior property manager'>",
  "routing_suggestion": "<which team or role should handle this, e.g. 'Property Manager', 'Accounts Team', 'Building Manager', 'Senior Manager - Escalation'>"
}

Classification guide:
- new_client_enquiry: person asking about signing up or engaging services
- support_request: existing client needing help with something
- complaint: client expressing dissatisfaction or lodging a formal complaint
- general_question: information request not requiring action
- billing_enquiry: questions about levies, invoices, payments, or financials
- maintenance_request: repair, inspection, or building maintenance related
- legal_matter: by-law disputes, legal notices, NCAT, or legal advice requests
- urgent_matter: safety issue, emergency, or time-critical situation

Return ONLY the JSON object. No explanation, no markdown, no extra text.`;

const senderLine = data.sender_name !== 'Unknown Client'
  ? `Sender: ${data.sender_name}${data.sender_email ? ' <' + data.sender_email + '>' : ''}`
  : 'Sender: Unknown';

const userMessage = `${senderLine}\n\nEnquiry:\n${data.enquiry}`;

const requestBody = {
  model: 'claude-3-5-sonnet-20241022',
  max_tokens: 1500,
  system: systemPrompt,
  messages: [
    {
      role: 'user',
      content: userMessage
    }
  ]
};

return [{
  json: {
    ...data,
    request_body: JSON.stringify(requestBody)
  }
}];

const httpResponse = $input.first().json;
const inputData = $('Build AI Request').first().json;

// Handle Anthropic API-level errors (auth, rate limit, etc.)
if (httpResponse.type === 'error') {
  return [{
    json: {
      success: false,
      http_status: 500,
      error: httpResponse.error?.type || 'api_error',
      message: httpResponse.error?.message || 'The AI service returned an error. Please check your API key and try again.'
    }
  }];
}

// Handle unexpected response structure
if (!httpResponse.content || !Array.isArray(httpResponse.content) || !httpResponse.content[0]?.text) {
  return [{
    json: {
      success: false,
      http_status: 500,
      error: 'unexpected_response',
      message: 'AI service returned an unexpected response format.',
      raw: JSON.stringify(httpResponse).substring(0, 300)
    }
  }];
}

const rawText = httpResponse.content[0].text.trim();

// Parse AI JSON response — handle accidental markdown wrapping
let aiResult;
try {
  const jsonMatch = rawText.match(/\{[\s\S]*\}/);
  if (!jsonMatch) throw new Error('No JSON object found in AI response');
  aiResult = JSON.parse(jsonMatch[0]);
} catch (parseErr) {
  return [{
    json: {
      success: false,
      http_status: 500,
      error: 'parse_error',
      message: `Could not parse AI response as JSON: ${parseErr.message}`,
      raw_response: rawText.substring(0, 500)
    }
  }];
}

// Validate classification is a known type, fall back gracefully
const validClassifications = [
  'new_client_enquiry', 'support_request', 'complaint', 'general_question',
  'billing_enquiry', 'maintenance_request', 'legal_matter', 'urgent_matter'
];
const classification = validClassifications.includes(aiResult.classification)
  ? aiResult.classification
  : 'general_question';

// Clamp confidence to 0–1
const confidenceRaw = typeof aiResult.confidence === 'number' ? aiResult.confidence : 0.5;
const confidence = Math.min(1, Math.max(0, confidenceRaw));

// Normalise urgency
const validUrgency = ['low', 'medium', 'high'];
const urgency = validUrgency.includes(aiResult.urgency) ? aiResult.urgency : 'medium';

return [{
  json: {
    success: true,
    http_status: 200,
    enquiry: {
      original_text: inputData.enquiry,
      sender_name: inputData.sender_name,
      sender_email: inputData.sender_email || null,
      sender_phone: inputData.sender_phone || null,
      received_at: inputData.timestamp
    },
    analysis: {
      classification: classification,
      confidence_score: confidence,
      confidence_percent: Math.round(confidence * 100) + '%',
      urgency: urgency,
      summary: aiResult.summary || 'No summary available',
      key_details: Array.isArray(aiResult.key_details) ? aiResult.key_details : []
    },
    staff_guidance: {
      recommended_action: aiResult.recommended_action || 'Review and respond manually',
      routing_suggestion: aiResult.routing_suggestion || 'General Enquiries Team',
      suggested_response: aiResult.suggested_response || 'No suggested response generated'
    },
    meta: {
      processed_at: new Date().toISOString(),
      model: 'claude-3-5-sonnet-20241022',
      tokens_used: httpResponse.usage
        ? { input: httpResponse.usage.input_tokens, output: httpResponse.usage.output_tokens }
        : null,
      workflow_version: '1.0.0'
    }
  }
}];

const data = $input.first().json;
return [{
  json: {
    success: false,
    http_status: 400,
    error: data.error,
    message: data.message
  }
}];
